// rusername © 2026
// author of idea Michael
// Исправленная версия стратегии EMA + MACD

//@version=6
strategy("EMA Slope Angle + MACD (Michael) v3", overlay=true, margin_long=100, margin_short=100, pyramiding=0)

// ═════════════════════════════════════════════════════════════════════════════
// ПАРАМЕТРЫ СТРАТЕГИИ
// ═════════════════════════════════════════════════════════════════════════════

// --- Параметры EMA ---
emaLength = input.int(50, "Период EMA тренда", minval=1, group="EMA")
slopeLookback = input.int(5, "Кол-во баров для расчета угла", minval=1, group="EMA")

risingAngleTrigger = input.float(0.2, "Порог угла восходящего тренда (°)", minval=0.1, step=0.01, group="Угловые параметры")
fallingAngleTrigger = input.float(-0.2, "Порог угла нисходящего тренда (°)", maxval=-0.1, step=0.01, group="Угловые параметры")
maxAngleSaturation = input.float(1.0, "Максимальный угол для насыщенности цвета (°)", minval=1.0, group="Угловые параметры")

uptrendColor = input.color(#006400, "цвет лонга", group="Цвета")
downtrendColor = input.color(#8B0000, "цвет шорта", group="Цвета")
flatColor = input.color(color.new(color.gray, 0), "цвет флэта", group="Цвета")

showSignals = input.bool(true, "Отображать изменения тренда", group="Сигналы")
exitByEMARgime = input.bool(false, "Выход из сделки, если угол EMA показал ФЛЭТ", group="Сигналы")

showAngleStats = input.bool(false, "Отображать угловую статистику", group="Угловая статистика")

// --- Опциональный фильтр EMA ---
useEmaFilterStandart = input.bool(true, "Использовать фильтр положения EMA и цены", group="EMA Filter")
useEmaFilter = input.bool(false, "Использовать фильтр угла EMA", group="EMA Filter")

// --- Параметры MACD ---
macdFast   = input.int(12, "Быстрая линия MACD", minval=1, group="MACD")
macdSlow   = input.int(26, "Медленная линия MACD", minval=1, group="MACD")
macdSignal = input.int(9, "Сигнальная линия MACD", minval=1, group="MACD")
useAntiNervous = input.bool(false,"анти-нервность при выходах",group="MACD")
AntiNervousLenght = input.int(3,"Период свечей для антинервозности при выходе по MACD", minval=1,maxval=10, group="MACD")
// --- Параметры Trailing Stop ---
useTrailing = input.bool(false, "Использовать Trailing Stop", group="Trailing Stop")
trailType = input.string("Percent", "Тип трейлинга", options=["Fixed", "Percent", "ATR"], group="Trailing Stop")
trailFixed = input.float(50, "Фиксированный отступ (пункты)", minval=1, group="Trailing Stop")
trailPercent = input.float(2.0, "Процентный отступ (%)", minval=0.1, step=0.1, group="Trailing Stop")
trailATRLen = input.int(14, "Период ATR", minval=1, group="Trailing Stop")
trailATRMult = input.float(1.5, "Множитель ATR", minval=0.1, step=0.1, group="Trailing Stop")
trailActivation = input.float(0, "Активация после прибыли (%)", minval=0, step=0.5, group="Trailing Stop", tooltip="0 = трейлинг с момента входа")

// ═════════════════════════════════════════════════════════════════════════════
// РАСЧЕТ ИНДИКАТОРОВ
// ═════════════════════════════════════════════════════════════════════════════

// ==============================
// EMA & РАСЧЕТ УГЛА
// ==============================

emaValue = ta.ema(close, emaLength)

ema_now = emaValue
ema_then = emaValue[slopeLookback]

delta = ema_now - ema_then

// УГОЛ В ГРАДУСАХ
angleDeg = math.atan(delta / slopeLookback) * 180 / math.pi

// ==============================
// ФАЗА РЫНКА
// ==============================

regime = angleDeg >= risingAngleTrigger ? "ЛОНГ" : angleDeg <= fallingAngleTrigger ? "ШОРТ" : "ФЛЭТ"

// ==============================
// ОПРЕДЕЛЕНИЕ ЦВЕТА EMA
// ==============================

normAngle = math.min(math.max(angleDeg / maxAngleSaturation, -1), 1)

// ПРОЗРАЧНОСТЬ ЦВЕТА EMA: БОЛЬШЕ УГОЛ = МЕНЬШЕ ПРОЗРАЧНОСТЬ (БОЛЬШЕ ВИДИМОСТЬ)
// ДИАПАЗОН: 0-50 ПРОЗРАЧНОСТИ (50-100% прозрачности) для лучшей видимости
transparency = 50 - int(math.abs(normAngle) * 50)

emaColor = regime == "ФЛЭТ" ? flatColor : angleDeg > 0 ? color.new(uptrendColor, transparency) : color.new(downtrendColor, transparency)

// MACD индикатор (стандартная функция TradingView)
[macdLine, signalLine, _] = ta.macd(close, macdFast, macdSlow, macdSignal)

// ATR для trailing stop
atr = ta.atr(trailATRLen)

// ==============================
// СИГНАЛЫ УГЛА EMA
// ==============================

var string lastRegime = ""
var string lastSignal = "НЕТ"
var bool upSignal = false
var bool downSignal = false

if barstate.isconfirmed and bar_index >= slopeLookback
    // СБРОС СИГНАЛОВ, ЕСЛИ ФЛЭТ
    if regime == "ФЛЭТ"
        lastSignal := "НЕТ"
    
    // СБРОС СИГНАЛОВ
    upSignal := false
    downSignal := false
    
    // ОПРЕДЕЛЯЕМ СМЕНУ С ФЛЭТА НА ВВЕРХ/ВНИЗ
    if showSignals and lastRegime == "ФЛЭТ" and regime != "ФЛЭТ"
        if angleDeg >= risingAngleTrigger and regime == "ЛОНГ"
            upSignal := true
            lastSignal := "ВВЕРХ"
        else if angleDeg <= fallingAngleTrigger and regime == "ШОРТ"
            downSignal := true
            lastSignal := "ВНИЗ"
    
    lastRegime := regime


// ═════════════════════════════════════════════════════════════════════════════
// ОПРЕДЕЛЕНИЕ НАПРАВЛЕНИЯ ДВИЖЕНИЯ MACD
// ═════════════════════════════════════════════════════════════════════════════

// MACD растет: текущее значение строго больше предыдущего
macdRising = macdLine > macdLine[1]

// MACD падает: текущее значение строго меньше предыдущего
macdFalling = macdLine < macdLine[1]

// Примечание: если macdLine == macdLine[1], то НЕ рост и НЕ падение

// ═════════════════════════════════════════════════════════════════════════════
// УСЛОВИЯ ДЛЯ СИГНАЛЬНОЙ СВЕЧИ
// ═════════════════════════════════════════════════════════════════════════════

// --- LONG сигнал ---
// 1. Закрытие выше EMA-21
// 2. MACD растет
// 3. Если MACD < 0: должен быть ВЫШЕ сигнальной линии (не обязательно пересечение)
//    Если MACD >= 0: положение относительно сигнальной линии не важно
longMacdOk = macdLine >= 0 ? macdRising : (macdRising and macdLine > signalLine)
longEmaOk = useEmaFilterStandart ? close > emaValue : true
longFilterOk = useEmaFilter ? angleDeg >= risingAngleTrigger : true

longSignal = longEmaOk and longMacdOk and longFilterOk

// --- SHORT сигнал ---
// 1. Закрытие ниже EMA-21
// 2. MACD падает
// 3. Если MACD > 0: должен быть НИЖЕ сигнальной линии (не обязательно пересечение)
//    Если MACD <= 0: положение относительно сигнальной линии не важно
shortMacdOk = macdLine <= 0 ? macdFalling : (macdFalling and macdLine < signalLine)
shortEmaOk = useEmaFilterStandart ? close < emaValue : true 
shortFilterOk = useEmaFilter ? angleDeg <= fallingAngleTrigger : true
shortSignal = shortEmaOk and shortMacdOk and shortFilterOk

// ═════════════════════════════════════════════════════════════════════════════
// ПЕРЕМЕННЫЕ ДЛЯ ХРАНЕНИЯ СТОПОВ
// ═════════════════════════════════════════════════════════════════════════════

var float longStopLevel = na   // Уровень stop-loss для long позиции
var float shortStopLevel = na  // Уровень stop-loss для short позиции
var float entryPrice = na      // Цена входа (для trailing stop)
var float trailStopLong = na   // Trailing stop для long
var float trailStopShort = na  // Trailing stop для short

// Текущая позиция
inLong = strategy.position_size > 0
inShort = strategy.position_size < 0
flat = strategy.position_size == 0

// ═════════════════════════════════════════════════════════════════════════════
// ФУНКЦИЯ РАСЧЕТА TRAILING STOP OFFSET
// ═════════════════════════════════════════════════════════════════════════════

getTrailOffset() =>
    offset = 0.0
    if trailType == "Fixed"
        offset := trailFixed * syminfo.mintick
    else if trailType == "Percent"
        offset := close * trailPercent / 100
    else if trailType == "ATR"
        offset := atr * trailATRMult
    offset

// ═════════════════════════════════════════════════════════════════════════════
// СБРОС ПЕРЕМЕННЫХ ПРИ ЗАКРЫТИИ ПОЗИЦИИ
// ═════════════════════════════════════════════════════════════════════════════

if flat
    longStopLevel := na
    shortStopLevel := na
    entryPrice := na
    trailStopLong := na
    trailStopShort := na

// ═════════════════════════════════════════════════════════════════════════════
// ЛОГИКА ВХОДА В ПОЗИЦИИ
// ═════════════════════════════════════════════════════════════════════════════

// Примечание: Pine Script выполняет код на ЗАКРЫТИИ свечи
// Поэтому когда мы получаем сигнал, это означает, что сигнальная свеча закрылась
// strategy.entry() откроет позицию на ОТКРЫТИИ следующей свечи (автоматически)

// --- Вход в LONG из flat позиции ---
if longSignal and flat
    // Сохраняем минимум сигнальной свечи (включая тень) для stop-loss
    longStopLevel := low
    // Открываем long позицию (исполнится на открытии следующей свечи)
    strategy.entry("Long", strategy.long, comment="Long Entry")

// --- Вход в SHORT из flat позиции ---
if shortSignal and flat
    // Сохраняем максимум сигнальной свечи (включая тень) для stop-loss
    shortStopLevel := high
    // Открываем short позицию (исполнится на открытии следующей свечи)
    strategy.entry("Short", strategy.short, comment="Short Entry")

// ═════════════════════════════════════════════════════════════════════════════
// РЕВЕРС ПОЗИЦИЙ (Long → Short и Short → Long)
// ═════════════════════════════════════════════════════════════════════════════

// --- Реверс: из LONG в SHORT ---
if shortSignal and inLong
    // Закрываем текущую long позицию
    strategy.close("Long", comment="Reverse to Short")
    // Сбрасываем trailing stop для long
    trailStopLong := na
    // Открываем short позицию
    shortStopLevel := high
    strategy.entry("Short", strategy.short, comment="Short Entry (Reverse)")

// --- Реверс: из SHORT в LONG ---
if longSignal and inShort
    // Закрываем текущую short позицию
    strategy.close("Short", comment="Reverse to Long")
    // Сбрасываем trailing stop для short
    trailStopShort := na
    // Открываем long позицию
    longStopLevel := low
    strategy.entry("Long", strategy.long, comment="Long Entry (Reverse)")

// ═════════════════════════════════════════════════════════════════════════════
// СОХРАНЕНИЕ ЦЕНЫ ВХОДА (для trailing stop)
// ═════════════════════════════════════════════════════════════════════════════

if strategy.position_size != 0 and na(entryPrice)
    entryPrice := strategy.position_avg_price

// ═════════════════════════════════════════════════════════════════════════════
// TRAILING STOP ЛОГИКА
// ═════════════════════════════════════════════════════════════════════════════

if useTrailing and not na(entryPrice)
    trailOffset = getTrailOffset()
    
    // --- Trailing Stop для LONG позиции ---
    if inLong
        // Расчет текущей прибыли в процентах
        profitPercent = (close - entryPrice) / entryPrice * 100
        
        // Проверяем, активирован ли trailing stop
        if profitPercent >= trailActivation
            // Рассчитываем новый уровень trailing stop
            newTrailStop = close - trailOffset
            
            // Обновляем trailing stop (только если он двигается вверх)
            if na(trailStopLong)
                trailStopLong := newTrailStop
            else
                trailStopLong := math.max(trailStopLong, newTrailStop)
            
            // Используем максимум из начального стопа и trailing stop
            longStopLevel := math.max(longStopLevel, trailStopLong)
    
    // --- Trailing Stop для SHORT позиции ---
    if inShort
        // Расчет текущей прибыли в процентах
        profitPercent = (entryPrice - close) / entryPrice * 100
        
        // Проверяем, активирован ли trailing stop
        if profitPercent >= trailActivation
            // Рассчитываем новый уровень trailing stop
            newTrailStop = close + trailOffset
            
            // Обновляем trailing stop (только если он двигается вниз)
            if na(trailStopShort)
                trailStopShort := newTrailStop
            else
                trailStopShort := math.min(trailStopShort, newTrailStop)
            
            // Используем минимум из начального стопа и trailing stop
            shortStopLevel := math.min(shortStopLevel, trailStopShort)

// ═════════════════════════════════════════════════════════════════════════════
// УСТАНОВКА STOP-LOSS ОРДЕРОВ
// ═════════════════════════════════════════════════════════════════════════════

// Stop-loss для LONG позиции
if inLong and not na(longStopLevel)
    strategy.exit("Long SL", from_entry="Long", stop=longStopLevel, comment="Long SL")

// Stop-loss для SHORT позиции
if inShort and not na(shortStopLevel)
    strategy.exit("Short SL", from_entry="Short", stop=shortStopLevel, comment="Short SL")

// ═════════════════════════════════════════════════════════════════════════════
// ВЫХОД ПО РАЗВОРОТУ MACD
// ═════════════════════════════════════════════════════════════════════════════

macdDownN = useAntiNervous ? ta.falling(macdLine, AntiNervousLenght) : true  // N баров падает подряд
macdUpN   = useAntiNervous ? ta.rising(macdLine, AntiNervousLenght) : true  // N баров растет подряд

// Закрытие LONG позиции при начале снижения MACD
// MACD начал падать = первая свеча где macdLine < macdLine[1]
if inLong and macdFalling and macdDownN
    strategy.close("Long", comment="Long Exit (MACD Down)")
    trailStopLong := na

// Закрытие SHORT позиции при начале роста MACD
// MACD начал расти = первая свеча где macdLine > macdLine[1]
if inShort and macdRising and macdUpN
    strategy.close("Short", comment="Short Exit (MACD Up)")
    trailStopShort := na

// Закрытие LONG позиции при смене режима EMA
// EMA Slope сменился на ФЛЭТ
if inLong and exitByEMARgime and regime == "ФЛЭТ"
    strategy.close("Long", comment="Long Exit (EMA SLOPE)")
    trailStopLong := na

// Закрытие SHORT позиции при смене режима EMA
// EMA Slope сменился на ФЛЭТ
if inShort and exitByEMARgime and regime == "ФЛЭТ"
    strategy.close("Short", comment="Short Exit (EMA SLOPE)")
    trailStopShort := na

// ==============================
// РАСЧЕТ СТАТИСТИКИ УГЛОВ
// ==============================

var int count0to02 = 0
var int count02to05 = 0
var int count05to1 = 0
var int count1to15 = 0
var int count15to2 = 0
var int count2to3 = 0
var int count3to5 = 0
var int count5to10 = 0
var int countOver10 = 0
var string lastSymbol = na
var string lastTimeframe = na

// СБРОС УГЛОВОЙ СТАТИСТИКИ, ЕСЛИ МЕНЯЕТСЯ ТИКЕР ИЛИ ТАЙМФРЕЙМ
if syminfo.ticker != lastSymbol or timeframe.period != lastTimeframe
    count0to02 := 0
    count02to05 := 0
    count05to1 := 0
    count1to15 := 0
    count15to2 := 0
    count2to3 := 0
    count3to5 := 0
    count5to10 := 0
    countOver10 := 0
    lastSymbol := syminfo.ticker
    lastTimeframe := timeframe.period

if showAngleStats and barstate.isconfirmed and bar_index >= slopeLookback
    absAngle = math.abs(angleDeg)
    
    if absAngle <= 0.2
        count0to02 += 1
    else if absAngle <= 0.5
        count02to05 += 1
    else if absAngle <= 1.0
        count05to1 += 1
    else if absAngle <= 1.5
        count1to15 += 1
    else if absAngle <= 2.0
        count15to2 += 1
    else if absAngle <= 3.0
        count2to3 += 1
    else if absAngle <= 5.0
        count3to5 += 1
    else if absAngle <= 10.0
        count5to10 += 1
    else
        countOver10 += 1

// ═════════════════════════════════════════════════════════════════════════════
// ВИЗУАЛИЗАЦИЯ НА ГРАФИКЕ
// ═════════════════════════════════════════════════════════════════════════════

// ==============================
// ОТРИСОВКА EMA
// ==============================

plot(emaValue, "EMA", color=emaColor, linewidth=2)

// Стрелки сигналов Long (только для новых входов из flat)
plotshape(longSignal and flat, title="Long Signal", style=shape.triangleup, 
          location=location.belowbar, color=color.green, size=size.small, text="LONG")

// Стрелки сигналов Short (только для новых входов из flat)
plotshape(shortSignal and flat, title="Short Signal", style=shape.triangledown, 
          location=location.abovebar, color=color.red, size=size.small, text="SHORT")

// Реверсы Long → Short
plotshape(shortSignal and inLong, title="Reverse to Short", style=shape.xcross, 
          location=location.abovebar, color=color.purple, size=size.tiny, text="REV↓")

// Реверсы Short → Long
plotshape(longSignal and inShort, title="Reverse to Long", style=shape.xcross, 
          location=location.belowbar, color=color.purple, size=size.tiny, text="REV↑")

// Отрисовка уровня stop-loss для long
plot(inLong and not na(longStopLevel) ? longStopLevel : na, 
     "Long Stop", color=color.red, linewidth=1, style=plot.style_linebr)

// Отрисовка уровня stop-loss для short
plot(inShort and not na(shortStopLevel) ? shortStopLevel : na, 
     "Short Stop", color=color.red, linewidth=1, style=plot.style_linebr)

// Закрашивание фона при активной позиции
bgcolor(inLong ? color.new(color.green, 95) : na, title="Long Position Background")
bgcolor(inShort ? color.new(color.red, 95) : na, title="Short Position Background")

// Рисуем стрелки (Для Slope EMA)
plotshape(
     series=upSignal and showSignals,
     title="СИГНАЛ ВВЕРХ",
     location=location.belowbar,
     color=uptrendColor,
     style=shape.triangleup,
     size=size.small
 )

plotshape(
     series=downSignal and showSignals,
     title="СИГНАЛ ВНИЗ",
     location=location.belowbar,
     color=downtrendColor,
     style=shape.triangledown,
     size=size.small
 )

// ═════════════════════════════════════════════════════════════════════════════
// ИНФОРМАЦИОННАЯ ТАБЛИЧКА (опционально)
// ═════════════════════════════════════════════════════════════════════════════

// Создаем табличку с информацией о текущей позиции
var table infoTable = table.new(position.top_right, 2, showAngleStats ? 19 : 10, border_width=1)

if barstate.islastconfirmedhistory or barstate.isconfirmed
    table.clear(infoTable,0,0)
    table.cell(infoTable, 0, 0, "Позиция:", text_color=color.white, bgcolor=color.gray, text_size=size.small)
    table.cell(infoTable, 1, 0, inLong ? "LONG" : inShort ? "SHORT" : "Нет", 
               text_color=color.white, bgcolor=inLong ? color.green : inShort ? color.red : color.gray, text_size=size.small)
    
    table.cell(infoTable, 0, 1, "Вход:", text_color=color.white, bgcolor=color.gray, text_size=size.small)
    table.cell(infoTable, 1, 1, not na(entryPrice) ? str.tostring(entryPrice, format.mintick) : "-", 
               text_color=color.white, bgcolor=color.gray, text_size=size.small)
    
    table.cell(infoTable, 0, 2, "Stop:", text_color=color.white, bgcolor=color.gray, text_size=size.small)
    stopLevel = inLong ? longStopLevel : inShort ? shortStopLevel : na
    table.cell(infoTable, 1, 2, not na(stopLevel) ? str.tostring(stopLevel, format.mintick) : "-", 
               text_color=color.white, bgcolor=color.gray, text_size=size.small)
    
    table.cell(infoTable, 0, 3, "P/L %:", text_color=color.white, bgcolor=color.gray, text_size=size.small)
    plPercent = strategy.position_size != 0 and not na(entryPrice) ? (inLong ? (close - entryPrice) : (entryPrice - close)) / entryPrice * 100 : 0
    table.cell(infoTable, 1, 3, str.tostring(plPercent, "#.##") + "%", 
               text_color=plPercent >= 0 ? color.green : color.red, bgcolor=color.gray, text_size=size.small)
    
    table.cell(infoTable, 0, 4, "MACD:", text_color=color.white, bgcolor=color.gray, text_size=size.small)
    macdStatus = macdRising ? "↑" : macdFalling ? "↓" : "="
    table.cell(infoTable, 1, 4, macdStatus, text_color=color.white, bgcolor=color.gray, text_size=size.small)
    
    table.cell(infoTable, 0, 5, "Trail:", text_color=color.white, bgcolor=color.gray, text_size=size.small)
    trailActive = (inLong and not na(trailStopLong)) or (inShort and not na(trailStopShort))
    table.cell(infoTable, 1, 5, useTrailing ? (trailActive ? "ON" : "OFF") : "Disabled", 
               text_color=color.white, bgcolor=trailActive ? color.green : color.gray, text_size=size.small)

    // ДЛИНА EMA
    table.cell(infoTable, 0, 6, "EMA длина", text_color=color.white, bgcolor=color.gray, text_size=size.small)
    table.cell(infoTable, 1, 6, str.tostring(emaLength), text_color=color.white,bgcolor=color.gray,  text_size=size.small)
    
    // ТУКУЩИЙ УГОЛ
    angleRounded = math.round(angleDeg * 10) / 10
    table.cell(infoTable, 0, 7, "УГОЛ", text_color=color.white, bgcolor=color.gray, text_size=size.small)
    table.cell(infoTable, 1, 7, str.tostring(angleRounded, "#.#") + "°", text_color=color.white,bgcolor=color.gray,  text_size=size.small)
    
    // ФАЗА РЫНКА
